import React, { useState } from 'react';
import { Link } from 'react-router-dom';

// Sample data for high-protein recipes
const highProteinRecipes = [
  // ... (recipe data remains the same)
];

const HomePage = () => {
  const [weight, setWeight] = useState('');
  const [unit, setUnit] = useState('kg');
  const [recommendations, setRecommendations] = useState(null);

  const handleCalculate = (e) => {
    e.preventDefault();
    const weightInKg = unit === 'lbs' ? weight / 2.20462 : parseFloat(weight);

    if (weightInKg > 0) {
      // Calculation logic
      const protein = (weightInKg * 1.6).toFixed(0);
      const fats = (weightInKg * 0.8).toFixed(0);
      const water = (weightInKg * 35 / 1000).toFixed(1);
      const totalCalories = (weightInKg * 33).toFixed(0); // Calculate total calories
      
      const proteinCalories = parseFloat(protein) * 4;
      const fatCalories = parseFloat(fats) * 9;
      const carbCalories = totalCalories - proteinCalories - fatCalories;
      const carbs = (carbCalories / 4).toFixed(0);

      const newRecommendations = { protein, fats, carbs, water, totalCalories };
      setRecommendations(newRecommendations);

      // --- NEW: Save goals to local storage ---
      localStorage.setItem('userGoals', JSON.stringify({
        proteinGoal: parseFloat(protein),
        calorieGoal: parseFloat(totalCalories)
      }));
    }
  };

  return (
    <div className="text-brand-text">
      {/* Hero Section */}
      <section className="text-center py-20 px-4">
        {/* ... (rest of the section remains the same) */}
      </section>

      {/* Daily Intake Calculator Section */}
      <section className="py-16 px-4 bg-white">
        <div className="max-w-4xl mx-auto">
          <h2 className="text-3xl md:text-4xl font-bold text-center text-brand-text mb-8">
            Get Your Personalized Daily Intake
          </h2>
          <div className="bg-brand-bg p-8 rounded-xl border border-gray-200">
            <form onSubmit={handleCalculate} className="flex flex-col md:flex-row items-center justify-center gap-4">
              {/* ... (form remains the same) */}
            </form>

            {recommendations && (
              <div className="mt-8 pt-8 border-t border-gray-200 grid grid-cols-2 md:grid-cols-5 gap-4 text-center">
                <div>
                  <p className="text-sm text-gray-500">Calories</p>
                  <p className="text-2xl font-bold text-brand-mint">{recommendations.totalCalories}</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Protein</p>
                  <p className="text-2xl font-bold text-brand-mint">{recommendations.protein}g</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Carbs</p>
                  <p className="text-2xl font-bold text-brand-mint">{recommendations.carbs}g</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Fats</p>
                  <p className="text-2xl font-bold text-brand-mint">{recommendations.fats}g</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Water</p>
                  <p className="text-2xl font-bold text-brand-mint">{recommendations.water}L</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </section>

      {/* ... (rest of the page remains the same) ... */}
    </div>
  );
};

export default HomePage;
